+
+// getEnvBool reads a boolean from environment variable with a default value
+func getEnvBool(key string, defaultValue bool) bool {
+	if val := os.Getenv(key); val != "" {
+		return val == "true" || val == "1"
+	}
+	return defaultValue
+}
